require"UI.UIBase"require"UI.UIBlock"UI_AchieveComplete=UIBase:Inherit()function UI_AchieveComplete:OnCreate()UI_AchieveComplete.Inst=self;self.achievementlst={}self.transform:SetRectPos(0,-130)self.timer=TimerMgr:Init()self.updatetimer=TimerMgr:Init()self.updatetimer:LoopFrame(1,-1,function()self:Update()end)end;function UI_AchieveComplete:OnShow(a)local b=ExcelMgr.GetData('achievement','achievement',self.achievementlst[1])if not b then table.remove(self.achievementlst,1)a("未找到成就数据")return end;if b.hidden==1 or b.deprecated==1 then table.remove(self.achievementlst,1)a("成就已废弃")return end;if self.show_lock then a("锁定中")return end;self.show_lock=true;self.transform.gameObject:SetActive(true)self:AnimAlphaIn(self.transform,{x=0,y=30},0.15,nil,function()a()end)self:SetRareImg(b.rare)self:CalcLabel(b['name_'..GameMgr.Inst.prefer_language])self.timer:Delay(1.6,function()table.remove(self.achievementlst,1)self:CloseSelf()end)self.timer:Delay(2.5,function()self.show_lock=false end)end;function UI_AchieveComplete:OnClose(a)self:AnimAlphaOut(self.transform,{x=0,y=0},0.15,0,function()self.transform.gameObject:SetActive(false)a()end)end;function UI_AchieveComplete:CalcLabel(c)local d=Tools.GetStringLength(c)if d<16 then self.name.text=c else local e=math.ceil(d/2)local f=Tools.UTF8Sub(c,1,e)local g=Tools.UTF8Sub(c,e+1,d-e)self.name.text=f..'\n'..g end end;function UI_AchieveComplete:SetRareImg(h)if h==1 then ImageMgr.SetTextureAsync(self.icon,"ui/common/main/pic/trophy_copper")elseif h==2 then ImageMgr.SetTextureAsync(self.icon,"ui/common/main/pic/trophy_sliver")elseif h==3 then ImageMgr.SetTextureAsync(self.icon,"ui/common/main/pic/trophy_gold")end end;function UI_AchieveComplete:Pop(i)table.insert(self.achievementlst,i)end;function UI_AchieveComplete:LockingAnim()self.locking_anim=true end;function UI_AchieveComplete:UnLockingAnim()self.locking_anim=false end;function UI_AchieveComplete:Update()if self.uiLifecycleState==EUILifecycleState.Inactive and not self.show_lock and#self.achievementlst>0 and not self.locking_anim then UIMgr.Inst:ShowUI(self.className)end end;return UI_AchieveComplete